export interface AccessTokenOptions {
  storageKey?: string
  paramName?: string
  saveToStorage?: boolean
  removeFromUrl?: boolean
}

export function getAccessToken(
  options: AccessTokenOptions = {}
): string | null {
  const {
    storageKey = 'vibe_coder_access_token',
    paramName = 'access_token',
    saveToStorage = true,
    removeFromUrl = true,
  } = options

  let token: string | null = null

  // Check URL params
  if (typeof window !== 'undefined' && window.location) {
    try {
      const urlParams = new URLSearchParams(window.location.search)
      token = urlParams.get(paramName)

      if (token) {
        if (saveToStorage) {
          saveAccessToken(token, { storageKey })
        }
        if (removeFromUrl) {
          urlParams.delete(paramName)
          const newUrl = `${window.location.pathname}${
            urlParams.toString() ? `?${urlParams.toString()}` : ''
          }${window.location.hash}`
          window.history.replaceState({}, document.title, newUrl)
        }
        return token
      }
    } catch (e) {
      console.error('Error retrieving token from URL:', e)
    }
  }

  // Check localStorage
  if (typeof window !== 'undefined' && window.localStorage) {
    try {
      token = window.localStorage.getItem(storageKey)
      return token
    } catch (e) {
      console.error('Error retrieving token from localStorage:', e)
    }
  }

  return null
}

export function saveAccessToken(
  token: string,
  options: Pick<AccessTokenOptions, 'storageKey'> = {}
): boolean {
  const { storageKey = 'vibe_coder_access_token' } = options

  if (typeof window === 'undefined' || !window.localStorage || !token) {
    return false
  }

  try {
    window.localStorage.setItem(storageKey, token)
    window.localStorage.setItem('token', token)
    return true
  } catch (e) {
    console.error('Error saving token to localStorage:', e)
    return false
  }
}

export function removeAccessToken(
  options: Pick<AccessTokenOptions, 'storageKey'> = {}
): boolean {
  const { storageKey = 'vibe_coder_access_token' } = options

  if (typeof window === 'undefined' || !window.localStorage) {
    return false
  }

  try {
    window.localStorage.removeItem(storageKey)
    return true
  } catch (e) {
    console.error('Error removing token from localStorage:', e)
    return false
  }
}
